import{_ as i,o as t,c as a,a2 as n}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"Chapter 6: File System Operations","description":"Implementing safe, reliable file reading, writing, and editing tools — the most fundamental operations a coding agent performs.","frontmatter":{"title":"Chapter 6: File System Operations","description":"Implementing safe, reliable file reading, writing, and editing tools — the most fundamental operations a coding agent performs."},"headers":[],"relativePath":"learn/linear/06-file-system-operations/index.md","filePath":"learn/linear/06-file-system-operations/index.md"}'),r={name:"learn/linear/06-file-system-operations/index.md"};function s(l,e,o,h,d,f){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="file-system-operations" tabindex="-1">File System Operations <a class="header-anchor" href="#file-system-operations" aria-label="Permalink to &quot;File System Operations&quot;">​</a></h1><p>Reading and writing files is the most fundamental thing a coding agent does. Every other capability -- code generation, refactoring, bug fixing, test writing -- ultimately reduces to reading source files, reasoning about them, and writing changes back to disk. Getting file operations right means getting them safe, fast, and resilient to the many edge cases that arise in real-world codebases.</p><p>This chapter covers the full spectrum of file system operations. We start with reading strategies that handle everything from small configuration files to massive log files. We then tackle writing with an emphasis on safety: atomic operations that prevent data corruption, backup strategies, and encoding-aware output. The core of the chapter addresses the editing problem -- how to modify existing files precisely using string replacement, patch-based approaches, and diff algorithms.</p><p>By the end of this chapter, you will have implemented a complete set of file operation tools for your agent. You will understand the trade-offs between different editing strategies, know how to handle large files without consuming excessive memory, and have cross-platform path handling that works on macOS, Linux, and Windows.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Implement file reading tools that handle encoding detection, line-range selection, and large files efficiently</li><li>Build safe file writing operations using atomic writes and temporary files to prevent data corruption</li><li>Design and implement a string-replacement-based editing tool that works reliably with LLM-generated inputs</li><li>Understand diff algorithms and when to use patch-based editing versus string replacement</li><li>Handle cross-platform path differences and Unicode edge cases in file content</li><li>Implement file watching for live-reload development workflows</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/linear/06-file-system-operations/01-file-reading-strategies.html">File Reading Strategies</a></li><li><a href="/linear/06-file-system-operations/02-writing-safely.html">Writing Safely</a></li><li><a href="/linear/06-file-system-operations/03-editing-approaches.html">Editing Approaches</a></li><li><a href="/linear/06-file-system-operations/04-string-replace-vs-patch.html">String Replace vs Patch</a></li><li><a href="/linear/06-file-system-operations/05-diff-algorithms.html">Diff Algorithms</a></li><li><a href="/linear/06-file-system-operations/06-atomic-operations.html">Atomic Operations</a></li><li><a href="/linear/06-file-system-operations/07-large-file-handling.html">Large File Handling</a></li><li><a href="/linear/06-file-system-operations/08-encoding-and-unicode.html">Encoding and Unicode</a></li><li><a href="/linear/06-file-system-operations/09-file-watching.html">File Watching</a></li><li><a href="/linear/06-file-system-operations/10-temporary-files.html">Temporary Files</a></li><li><a href="/linear/06-file-system-operations/11-cross-platform-paths.html">Cross Platform Paths</a></li><li><a href="/linear/06-file-system-operations/12-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 5 (tool system concepts)</li></ul>',10)])])}const c=i(r,[["render",s]]);export{p as __pageData,c as default};
